targets.expr:
sum by (phase) (
  label_replace(
    kube_pod_status_phase{
      namespace="$namespace",
      phase=~"Running|Pending|Failed|Succeeded|Unknown"
    }
    * on (namespace, pod)
      group_left(owner_name)
      kube_pod_owner{
        namespace="$namespace",
        owner_kind="ReplicaSet",
        owner_name=~".*sas.*"
      },
    "deployment", "$1", "owner_name", "(.+)-[a-f0-9]{9,10}$"
  )
)

kube_persistentvolumeclaim_resource_requests_storage_bytes{
  namespace="$namespace"
}
* on (namespace, persistentvolumeclaim)
  group_left(storageclass, volume, volumemode)
  kube_persistentvolumeclaim_info{
    namespace="$namespace"
  }

count by (job_group) (
  label_replace(
    kube_job_status_succeeded{
      namespace="$namespace",
      job_name=~".*-[0-9]+"
    } > 0,
    "job_group",
    "$1",
    "job_name",
    "(.*)-[0-9]+"
  )
)
